import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

// Deterministic minute-by-minute throughput with a traffic burst around x=38,
// so there is something worth zooming into.
function mulberry32(seed) {
  return function () {
    seed |= 0
    seed = (seed + 0x6d2b79f5) | 0
    var t = Math.imul(seed ^ (seed >>> 15), 1 | seed)
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296
  }
}

var rand = mulberry32(7)
var trafficData = []
var level = 40
for (var i = 1; i <= 60; i++) {
  level += (rand() - 0.5) * 12
  if (level < 15) level = 15
  var y = level
  if (i >= 32 && i <= 44) {
    y += 70 * Math.exp(-Math.pow(i - 38, 2) / 8)
  }
  trafficData.push([i, Math.round(y)])
}

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Throughput',
        data: trafficData,
      },
    ],
    options: {
      chart: {
        type: 'line',
        height: 400,
        zoom: {
          enabled: true,
          type: 'x',
          autoScaleYaxis: false,
        },
        toolbar: {
          autoSelected: 'zoom',
        },
        animations: { enabled: false },
      },
      title: {
        text: 'Network Throughput (Mbps)',
        align: 'left',
      },
      subtitle: {
        text: 'Drag to zoom into the traffic burst around minute 38',
        align: 'left',
      },
      dataLabels: { enabled: false },
      markers: { size: 0 },
      xaxis: {
        type: 'numeric',
        title: {
          text: 'Minute',
        },
      },
      yaxis: { min: 0 },
      stroke: { curve: 'monotoneCubic' },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="line"
          height={400}
        />
      </div>
    </div>
  )
}

export default ApexChart
